diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 999ad1adff20..353f7dacb9b1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -472,11 +472,10 @@ Instruction *InstCombinerImpl::foldSelectOpOp(SelectInst &SI, Instruction *TI,
   // Cond ? x/y : x/z --> x / (Cond ? y : z)
   auto *BO = dyn_cast<BinaryOperator>(TI);
   if (BO && BO->isIntDivRem() && !isGuaranteedNotToBePoison(Cond)) {
-    // A udiv/urem with a common divisor is safe because UB can only occur with
-    // div-by-zero, and that would be present in the original code.
-    if (BO->getOpcode() == Instruction::SDiv ||
-        BO->getOpcode() == Instruction::SRem || MatchIsOpZero)
-      Cond = Builder.CreateFreeze(Cond);
+    // Freezing is required to avoid introducing immediate UB from a poison
+    // condition when sinking div/rem through a select. Conservatively freeze the
+    // condition for all integer div/rem when it may be poison.
+    Cond = Builder.CreateFreeze(Cond);
   }

   // If we reach here, they do have operations in common.
diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index d08be1e55c85..9c347dceb7ee 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -1061,6 +1061,27 @@ static bool isDivZero(Value *X, Value *Y, const SimplifyQuery &Q,

   // IsSigned == false.

+  // Avoid over-aggressive folding for vectors: only proceed with unsigned
+  // reasoning when the divisor is a uniform constant across lanes. Otherwise,
+  // per-lane conditions may not hold globally, and folding X / Y -> 0 would be
+  // incorrect.
+  if (X->getType()->isVectorTy()) {
+    auto *CVec = dyn_cast<Constant>(Y);
+    if (!CVec || !isa<FixedVectorType>(Y->getType())) {
+      return false;
+    }
+    // Ensure all elements are the same constant.
+    auto *VTy = cast<FixedVectorType>(Y->getType());
+    Constant *First = CVec->getAggregateElement(0u);
+    if (!First)
+      return false;
+    for (unsigned i = 1, e = VTy->getNumElements(); i != e; ++i) {
+      Constant *Elt = CVec->getAggregateElement(i);
+      if (!Elt || Elt != First)
+        return false;
+    }
+  }
+
   // Is the unsigned dividend known to be less than a constant divisor?
   // TODO: Convert this (and above) to range analysis
   //      ("computeConstantRangeIncludingKnownBits")?
